mapper.select:
select * from
reginfotable,busertable,testinfoRoom,roomtable,testinfotable,testtable
where reginfotable.user_id=busertable.user_id and
reginfotable.testinfoRoom_id=testinfoRoom.testinfoRoom_id and
testinfoRoom.room_id=roomtable.room_id and
testinfoRoom.testinfo_id = testinfotable.testinfo_id and
testinfotable.test_id = testtable.test_id and ""=""

	and reginfo_id = #{reginfo_id}


	and reginfotable.user_id = #{user_id}


	and reginfotable.testinfoRoom_id = #{testinfoRoom_id}


	and ticketnum = #{ticketnum}


	and reginfotable.status = #{status}


	and reginfotable.submit_time = #{submit_time}


	and testinfotable.testinfo_id = #{testinfo_id}
